TeamManager = {}

TeamManager.teams = {}

--创建队伍的肌肉量限制
TeamManager.CreateTeamLimit = 1000
--加入队伍的等待时间
TeamManager.WaitTimeJoinTeam = 15
--加入队伍的肌肉量限制
TeamManager.JoinTeamMuscleLimit = 0.2

--初始的光环半径大小
TeamManager.InitEffectRange = 10
--队员肌肉量收益比例
TeamManager.MemberIncomeRatio = 0.1
--队长金币收益比例
TeamManager.CaptainIncomeRatio = 0.1

--是否加入队伍成为队员
function TeamManager:isJoinTeam(player)

    for _, team in pairs(self.teams) do
        if team:isJoinTeam(player.userId) then
            return true
        end
    end
    return false

end

function TeamManager:getTeamCaptain(player)
    for _, team in pairs(self.teams) do
        if team:isJoinTeam(player.userId) then
            return team:getCaptainUserId()
        end
    end
    return nil
end

function TeamManager:countLength(captainPlayer, player)
    local cPos = captainPlayer:getPosition()
    local pPos = player:getPosition()
    local sqr = math.pow(cPos.x - pPos.x, 2) + math.pow(cPos.y - pPos.y, 2) + math.pow(cPos.z - pPos.z, 2)
    return math.sqrt(sqr)
end

function TeamManager:isEnterTeamRange(captainPlayer, player)
    return self:countLength(captainPlayer, player) <= captainPlayer.property:getScale() * self.InitEffectRange
end


--是否创建队伍成为队长且队伍有队员了
function TeamManager:isTeamCreateSuccess(player)
    local team = self.teams[tostring(player.userId)]
    if not team then
        return false
    end
    return team:isHaveMember()
end

--肌肉量达到限制且未组队情况创建队伍
function TeamManager:createTeam(player)
    --肌肉限制
    if player.property.muscleMass < self.CreateTeamLimit then
        return
    end

    --伪装弱小不需要创建队伍
    if player.property.isConcealPower then
        return
    end

    --不是锻炼模式不需要创建队伍
    if not player.property.isWorkoutMode then
        return
    end

    --抓取物件的时候不需要创建队伍
    if player:isGrab() then
        return
    end

    --是否已经创建队伍
    if self.teams[tostring(player.userId)] ~= nil then
        return
    end

    --是否已经组队
    if self:isJoinTeam(player) then
        return
    end

    --创建队伍
    self.teams[tostring(player.userId)] = GameTeam.new(player.userId)
end

--队长死亡或者退出销毁队伍，或者队长加入其他队伍销毁队伍
function TeamManager:destroyTeam(player)
    if not player then
        return
    end

    local team = self.teams[tostring(player.userId)]
    if team == nil then
        return
    end

    local members = team:copyTeamMember()

    --解散
    team:disband()
    self.teams[tostring(player.userId)] = nil

    --队员中是否有条件创建队伍
    for _, userId in pairs(members) do
        local otherPlayer = PlayerManager:getPlayerByUserId(userId)
        if otherPlayer then
            self:createTeam(otherPlayer)
        end
    end
end


--
function TeamManager:readyJoinTeam(player)

    --是否已经组队
    if self:isJoinTeam(player) or self:isTeamCreateSuccess(player) then
        return
    end

    local captainPlayer = PlayerManager:getPlayerByUserId(player.teamId)

    if captainPlayer == nil or self.teams[tostring(captainPlayer.userId)] == nil then
        return
    end

    --检查肌肉量是否达到限制
    if player.property.muscleMass > captainPlayer.property.muscleMass * self.JoinTeamMuscleLimit then
        return
    end

    local oldTeamId = player.teamId
    local oldJoinTime = player.joinTime

    --print("TeamManager:readyJoinTeam "..tostring(player.userId))
    LuaTimer:schedule(function(userId, oldTeamId, oldJoinTime)
        local c_player = PlayerManager:getPlayerByUserId(userId)
        if not c_player then
            return
        end
        self:joinTeam(c_player, oldTeamId, oldJoinTime)
    end, self.WaitTimeJoinTeam * 1000, nil, player.userId, oldTeamId, oldJoinTime)

end

--加入队伍（是否已经组队、是否达到时间限制）
function TeamManager:joinTeam(player, oldTeamId, oldJoinTime)


    --是否在光圈内呆了一段时间
    if player.teamId ~= oldTeamId or player.joinTime ~= oldJoinTime then
        return
    end

    --是否已经组队
    if self:isJoinTeam(player) or self:isTeamCreateSuccess(player) then
        return
    end

    local captainPlayer = PlayerManager:getPlayerByUserId(player.teamId)
    if captainPlayer == nil then
        return
    end
    local team = self.teams[tostring(captainPlayer.userId)]
    if team == nil then
        return
    end

    --检查肌肉量是否达到限制
    if player.property.muscleMass > captainPlayer.property.muscleMass * self.JoinTeamMuscleLimit then
        return
    end

    --检查是否还在光圈内
    if not self:isEnterTeamRange(captainPlayer, player) then
        return
    end

    --看自己是否创建过队伍
    if self.teams[tostring(player.userId)] ~= nil then
        self.teams[tostring(player.userId)]:disband()
        self.teams[tostring(player.userId)] = nil
    end

    team:joinTeam(player)
end


--退出队伍(主动退出或肌肉量达到上线或队员死亡)
function TeamManager:exitTeam(player)
    for _, team in pairs(self.teams) do
        if team:isJoinTeam(player.userId) then
            team:exitTeam(player)
        end
    end
end

function TeamManager:onChangeMuscleMass(player)
    --如果是队长，看肌肉量是否解散队伍
    if self.teams[tostring(player.userId)] ~= nil then
        if player.property.muscleMass < self.CreateTeamLimit then
            self:destroyTeam(player)
        end
    elseif self:isJoinTeam(player) then
        --如果是队员，看肌肉量是否超出组队限制
        local captainPlayer = PlayerManager:getPlayerByUserId(self:getTeamCaptain(player))
        if captainPlayer and
                player.property.muscleMass > captainPlayer.property.muscleMass * self.JoinTeamMuscleLimit then
            self:exitTeam(player)
            self:createTeam(player)
        end
    else
        --尝试创建队伍
        self:createTeam(player)
    end

end

--将所有队长玩家身边的未加入队伍且在光环内的
--玩家设置成准备加入状态
function TeamManager:onCaptainPlayerMove(player)
    local team = self.teams[tostring(player.userId)]
    if team == nil then
        return
    end

    local otherPlayers = PlayerManager:getPlayers()

    for _, otherPlayer in pairs(otherPlayers) do
        if not self:isJoinTeam(otherPlayer) and not self:isTeamCreateSuccess(otherPlayer)
                and self:isEnterTeamRange(player, otherPlayer) and ((player.property.muscleMass * self.JoinTeamMuscleLimit > otherPlayer.property.muscleMass and os.time() - otherPlayer.joinTime >= self.WaitTimeJoinTeam + 1)
                or otherPlayer.teamId ~= tostring(player.userId)) and tostring(otherPlayer.userId) ~= tostring(player.userId) then
            otherPlayer.teamId = tostring(player.userId)
            otherPlayer.joinTime = os.time()
            self:readyJoinTeam(otherPlayer)
        end
    end

    local members = team:getMembers()
    for _, userId in pairs(members) do
        local otherPlayer = PlayerManager:getPlayerByUserId(userId)
        if otherPlayer and not self:isEnterTeamRange(player, otherPlayer) then
            self:exitTeam(otherPlayer)
            self:createTeam(otherPlayer)
        end
    end
end

--队员找最近的队长加入队伍
function TeamManager:onMemberPlayerMove(player)

    local temp = {}
    for _, team in pairs(self.teams) do
        local otherPlayer = PlayerManager:getPlayerByUserId(team:getCaptainUserId())
        if otherPlayer and self:isEnterTeamRange(otherPlayer, player) and tostring(otherPlayer.userId) ~= tostring(player.userId) then
            table.insert(temp, {
                userId = otherPlayer.userId,
                sqr = self:countLength(otherPlayer, player)
            })
        end
    end

    table.sort(temp, function(a, b)
        return a.sqr < b.sqr
    end)

    if #temp >= 1 then
        local otherPlayer = PlayerManager:getPlayerByUserId(temp[1].userId)
        if otherPlayer and self:isEnterTeamRange(otherPlayer, player) and
                ((player.property.muscleMass < otherPlayer.property.muscleMass * self.JoinTeamMuscleLimit and os.time() - player.joinTime >= self.WaitTimeJoinTeam + 1)
                        or player.teamId ~= tostring(otherPlayer.userId)) then
            player.teamId = tostring(otherPlayer.userId)
            player.joinTime = os.time()
            self:readyJoinTeam(player)
        end
    else
        self:exitTeam(player)
        self:createTeam(player)
    end

end

function TeamManager:onPlayerMove(player)

    --检查队员是否超出组队范围
    if self:isJoinTeam(player) then

        local captainPlayer = PlayerManager:getPlayerByUserId(self:getTeamCaptain(player))
        --队长会变化，交给循环
        if captainPlayer and not self:isEnterTeamRange(captainPlayer, player) then
            self:exitTeam(player)
            self:createTeam(player)
        end

        --队长移动、检查队员是否超出组队范围
    elseif self:isTeamCreateSuccess(player) then

        self:onCaptainPlayerMove(player)
        --引发队长会变化，交给循环
    else
        if self.teams[tostring(player.userId)] ~= nil then
            self:onCaptainPlayerMove(player)
        end

        --查找光圈内且最靠近玩家的队长
        self:onMemberPlayerMove(player)
    end

end

function TeamManager:onPlayerExit(player)
    if self:isJoinTeam(player) then
        self:exitTeam(player)
    elseif self:isTeamCreateSuccess(player) then
        self:destroyTeam(player)
    elseif self.teams[tostring(player.userId)] ~= nil then
        self.teams[tostring(player.userId)] = nil
    end
end

function TeamManager:onPlayerLogin(player)
    --尝试创建队伍
    local teamIds = {}
    for _, team in pairs(self.teams) do
        table.insert(teamIds, team:getCaptainUserId())
    end
    GamePacketSender:SendAllTeamInfo(player.rakssid, teamIds)
    self:createTeam(player)
end

function TeamManager:tick(ticks)

    local otherPlayers = PlayerManager:getPlayers()

    for _, otherPlayer in pairs(otherPlayers) do
        if not self:isJoinTeam(otherPlayer) and not self:isTeamCreateSuccess(otherPlayer) then
            self:onMemberPlayerMove(otherPlayer)
        end
    end

end

--计算收益
function TeamManager:countPlayerIncome(player)
    if TeamManager:isJoinTeam(player) then
        local itemPlayer = FitnessEquipConfig:getFitnessEquipConfig(player.property.fitnessEquipId)
        if itemPlayer == nil then
            itemPlayer = TokenFitnessEquipConfig:getFitnessEquipConfig(player.property.fitnessEquipId)
        end

        local captainPlayer = PlayerManager:getPlayerByUserId(self:getTeamCaptain(player))
        local itemCaptainPlayer

        if captainPlayer then
            itemCaptainPlayer = FitnessEquipConfig:getFitnessEquipConfig(captainPlayer.property.fitnessEquipId)
            if itemCaptainPlayer == nil then
                itemCaptainPlayer = TokenFitnessEquipConfig:getFitnessEquipConfig(player.property.fitnessEquipId)
            end
        end

        if itemPlayer and captainPlayer and itemCaptainPlayer then
            local x = itemCaptainPlayer.weight --组队额外肌肉值基数
            local k = captainPlayer.property.level --队长进阶数
            local m = player.property.muscleMass --队员当前肌肉上限值
            local y = math.min(x, self.MemberIncomeRatio * k * m) --健身时额外肌肉收益
            player.property:changeMuscleMass(math.ceil(y))
            captainPlayer.property:changeGold(math.ceil(itemPlayer.weight * self.CaptainIncomeRatio))
        end
    end
end

return TeamManager